// background.js - KTX 자동 예매 도우미

let searchInterval = null;
let isRunning = false;
let attemptCount = 0;
const logs = [];

function saveLog(msg, level = '') {
  const now = new Date();
  const t = `${String(now.getHours()).padStart(2,'0')}:${String(now.getMinutes()).padStart(2,'0')}:${String(now.getSeconds()).padStart(2,'0')}`;
  const entry = { msg: `[${t}] ${msg}`, type: level };
  logs.push(entry);
  if (logs.length > 50) logs.shift();
  chrome.storage.local.set({ ktxLogs: logs });
  // popup/extension page로 전송
  chrome.runtime.sendMessage({ type: 'log', text: msg, level }).catch(() => {});
  // content script(코레일 탭)로 전송
  getKorailTab().then(tab => {
    if (tab) chrome.tabs.sendMessage(tab.id, { type: 'log', text: msg, level }).catch(() => {});
  }).catch(() => {});
}

function sendAttempt(n) {
  chrome.storage.local.set({ ktxAttempts: n });
  chrome.runtime.sendMessage({ type: 'attempt', count: n }).catch(() => {});
}

function stopSearch(reason = '중지됨') {
  if (!isRunning) return;
  isRunning = false;
  if (searchInterval) { clearInterval(searchInterval); searchInterval = null; }
  chrome.storage.local.set({ ktxRunning: false });
  saveLog(reason, 'warn');
  chrome.runtime.sendMessage({ type: 'status', running: false }).catch(() => {});
}

async function getKorailTab() {
  const tabs = await chrome.tabs.query({});
  return tabs.find(t => t.url && (
    t.url.includes('korail.com/ticket/search/list') ||
    t.url.includes('korail.com/ticket')
  )) || null;
}

async function doSearch() {
  if (!isRunning) return; // 중지됐으면 즉시 종료

  attemptCount++;
  sendAttempt(attemptCount);
  saveLog(`#${attemptCount} 빈자리 확인 중...`);

  const tab = await getKorailTab();
  if (!isRunning) return; // await 이후 재확인
  if (!tab) {
    saveLog('⚠️ korail.com 예매 탭이 없습니다.', 'error');
    return;
  }

  try {
    await chrome.tabs.sendMessage(tab.id, { action: 'ping' }).catch(async () => {
      if (!isRunning) return;
      console.log('[KTX background] content.js 재주입');
      await chrome.scripting.executeScript({ target: { tabId: tab.id }, files: ['content.js'] });
      await new Promise(r => setTimeout(r, 500));
    });

    if (!isRunning) return; // 재주입 후 재확인

    const { ktxAllowStanding, ktxAllowWaiting, ktxTime1, ktxTime2 } = await chrome.storage.local.get(['ktxAllowStanding', 'ktxAllowWaiting', 'ktxTime1', 'ktxTime2']);
    console.log('[KTX BG] 설정:', { ktxAllowStanding, ktxAllowWaiting, ktxTime1, ktxTime2 });
    if (!isRunning) return;

    // MAIN world에서 직접 탐색 + 클릭 실행
    const results = await chrome.scripting.executeScript({
      target: { tabId: tab.id },
      world: 'MAIN',
      func: (allowStanding, allowWaiting, time1, time2) => {
        const tckLists = document.querySelectorAll('.tckList');
        if (!tckLists.length) return { found: false, message: '열차 목록 없음' };

        for (const tck of tckLists) {
          // gen(일반실) → spe(특실) → yms(입석+좌석) 순서 정렬
          const boxes = Array.from(tck.querySelectorAll('.price_box')).sort((a, b) => {
            const order = el => el.classList.contains('gen') ? 0 : el.classList.contains('spe') ? 1 : 2;
            return order(a) - order(b);
          });
          // 열차 시간 필터
          const trainTimeText = tck.querySelector('.data_box h3')?.textContent || tck.textContent;
          const tMatch = trainTimeText.match(/\((\d{2}):(\d{2})/);
          if (tMatch) {
            const trainHHMM = tMatch[1] + tMatch[2]; // "1030" 형태
            const t1 = time1 ? time1.replace(':', '') : '';
            const t2 = time2 ? time2.replace(':', '') : '';
            if (t1 && trainHHMM < t1) continue; // 시작 시간 이전
            if (t2 && trainHHMM > t2) continue; // 종료 시간 이후
          }

          for (const box of boxes) {
            // 완전 매진 → 항상 스킵
            if (box.classList.contains('sold_out')) continue;
            // 대기열차 특실 매진 → 항상 스킵
            if (box.classList.contains('sold_out_wait')) continue;
            if (box.classList.contains('active')) continue;
            if (box.querySelector('.inner')?.textContent.trim() === '-') continue;

            // 입석+좌석 가능 → allowStanding 필요
            if (box.classList.contains('yms') && !allowStanding) continue;
            // 입석+좌석 예약대기 → allowStanding 또는 allowWaiting 중 하나만 있으면 OK
            if (box.classList.contains('yms_wait') && !allowStanding && !allowWaiting) continue;
            // 일반실 예약대기 → allowWaiting 필요
            if (box.classList.contains('wait') && !allowWaiting) continue;

            const link = box.querySelector('a');
            if (!link) continue;

            const trainName = (tck.querySelector('.blind')?.textContent || '') +
                              (tck.querySelector('.num')?.textContent || '');
            const seatLabel = box.querySelector('.txt_ch')?.textContent?.trim() ||
                              box.querySelector('.tck_etc_use')?.textContent?.trim() || '';
            const price = box.querySelector('.txt_price')?.textContent?.trim() || '';

            // React onClick 직접 실행
            const key = Object.keys(link).find(k => k.startsWith('__reactEventHandlers'));
            const onClick = link[key]?.onClick;
            if (onClick) {
              let defaultPrevented = false;
              const fakeEvent = {
                target: link, currentTarget: link,
                bubbles: true, cancelable: true, defaultPrevented: false,
                preventDefault: function() { defaultPrevented = true; this.defaultPrevented = true; },
                stopPropagation: function() {},
                stopImmediatePropagation: function() {},
                nativeEvent: { preventDefault: function() {}, stopPropagation: function() {} },
                persist: function() {}, type: 'click',
              };
              onClick(fakeEvent);
            } else {
              link.click();
            }

            return { found: true, trainInfo: `${trainName} ${seatLabel} ${price}` };
          }
        }
        return { found: false, message: `${tckLists.length}개 열차 확인 — 빈자리 없음` };
      },
      args: [!!ktxAllowStanding, !!ktxAllowWaiting, ktxTime1 || '', ktxTime2 || '']
    });

    const res = results?.[0]?.result;
    console.log('[KTX BG] 검색 결과:', JSON.stringify(res));
    if (!isRunning) return;

    if (res?.found) {
      saveLog(`✅ 빈자리 발견: ${res.trainInfo}`, 'success');
      chrome.runtime.sendMessage({ type: 'found' }).catch(() => {});
      // 탐색 일시정지
      if (searchInterval) { clearInterval(searchInterval); searchInterval = null; }
      saveLog('⏸ 예매 진행 중 — 탐색 일시정지', 'info');
      // 1. 좌석 클릭 후 이용안내 팝업 먼저 처리 (노선에 따라 팝업 있을 수 있음)
      // 2. 팝업 없으면 바로 reservbtn 클릭
      setTimeout(() => clickPopupOrReserveBtn(tab.id), 800);
    } else {
      saveLog(res?.message || '빈자리 없음');
      if (!isRunning) return;
      await chrome.tabs.sendMessage(tab.id, { action: 'refresh' }).catch(() => {});
    }
  } catch (err) {
    if (!isRunning) return;
    saveLog(`오류: ${err.message} — content.js 재주입 시도`, 'warn');
    try {
      await chrome.scripting.executeScript({ target: { tabId: tab.id }, files: ['content.js'] });
    } catch(e) {
      saveLog(`재주입 실패: ${e.message}`, 'error');
    }
  }
}

function startSearch() {
  if (isRunning) stopSearch();
  isRunning = true;
  attemptCount = 0;
  logs.length = 0;
  saveLog('탐색 시작', 'info');

  doSearch();
  searchInterval = setInterval(() => {
    if (!isRunning) { clearInterval(searchInterval); return; }
    doSearch();
  }, 5000); // 5초 간격 고정
}

// 좌석 클릭 후: 팝업 있으면 확인 → reservbtn / 팝업 없으면 바로 reservbtn
async function clickPopupOrReserveBtn(tabId, attempt = 0) {
  if (!isRunning) return;
  if (attempt > 25) {
    saveLog('reservbtn 직접 시도', 'info');
    clickReserveBtnInMainWorld(tabId);
    return;
  }

  const results = await chrome.scripting.executeScript({
    target: { tabId },
    world: 'MAIN',
    func: () => {
      const YES = ['확인', '네', '예', '동의'];
      const POPUP_SELS = [
        '.ReactModal__Content', '.layerWrap', '.popup', '.pop_wrap',
        '.modal', '.layer_pop', '[role="dialog"]', '[role="alertdialog"]'
      ];

      // 팝업 있는지 확인
      for (const sel of POPUP_SELS) {
        const modal = document.querySelector(sel);
        if (!modal || modal.offsetParent === null) continue;
        const btns = modal.querySelectorAll('button, a');
        for (const btn of btns) {
          const text = btn.textContent.trim();
          if (YES.includes(text) && !btn.disabled && btn.offsetParent !== null) {
            const key = Object.keys(btn).find(k => k.startsWith('__reactEventHandlers'));
            const onClick = btn[key]?.onClick;
            if (onClick) {
              onClick({
                target: btn, currentTarget: btn, bubbles: true, cancelable: true,
                defaultPrevented: false,
                preventDefault: function() { this.defaultPrevented = true; },
                stopPropagation: function() {},
                stopImmediatePropagation: function() {},
                nativeEvent: { preventDefault: function() {}, stopPropagation: function() {} },
                persist: function() {}, type: 'click',
              });
            } else { btn.click(); }
            return { action: 'popup', text };
          }
        }
      }

      // 팝업 없으면 reservbtn 확인
      const wrap = document.querySelector('.reservbtnWrap');
      const reservBtn = wrap?.querySelector('button.reservbtn:not([disabled]):not(.btn-disabled)');
      return { action: reservBtn ? 'reservbtn_ready' : 'waiting' };
    }
  }).catch(() => [{ result: { action: 'waiting' } }]);

  const res = results?.[0]?.result;

  if (res?.action === 'popup') {
    saveLog(`이용안내 팝업 "${res.text}" 클릭`, 'success');
    // 팝업 닫힌 후 reservbtn 대기
    setTimeout(() => clickReserveBtnInMainWorld(tabId), 600);
  } else if (res?.action === 'reservbtn_ready') {
    // 팝업 없고 reservbtn 바로 있음
    clickReserveBtnInMainWorld(tabId);
  } else {
    // 아직 대기 중
    setTimeout(() => clickPopupOrReserveBtn(tabId, attempt + 1), 200);
  }
}

// MAIN world에서 reservbtn 클릭
async function clickReserveBtnInMainWorld(tabId, attempt = 0) {
  if (!isRunning) return;
  if (attempt > 20) { saveLog('⚠️ reservbtn 못 찾음', 'warn'); return; }

  const results = await chrome.scripting.executeScript({
    target: { tabId },
    world: 'MAIN',
    func: () => {
      const wrap = document.querySelector('.reservbtnWrap');
      if (!wrap) return { found: false };
      const btn = wrap.querySelector('button.reservbtn:not([disabled]):not(.btn-disabled)');
      if (!btn) return { found: false };

      const key = Object.keys(btn).find(k => k.startsWith('__reactEventHandlers'));
      const onClick = btn[key]?.onClick;
      if (onClick) {
        let defaultPrevented = false;
        const fakeEvent = {
          target: btn, currentTarget: btn,
          bubbles: true, cancelable: true, defaultPrevented: false,
          preventDefault: function() { defaultPrevented = true; this.defaultPrevented = true; },
          stopPropagation: function() {},
          stopImmediatePropagation: function() {},
          nativeEvent: { preventDefault: function() {}, stopPropagation: function() {} },
          persist: function() {}, type: 'click',
        };
        onClick(fakeEvent);
      } else {
        btn.click();
      }
      return { found: true, text: btn.textContent.trim() };
    }
  }).catch(() => [{ result: { found: false } }]);

  const res = results?.[0]?.result;
  if (res?.found) {
    saveLog(`예매 버튼 클릭: "${res.text}"`, 'success');
    // reservbtn 클릭 후 MutationObserver 활성화 → 이용안내 팝업 자동 처리
    await chrome.scripting.executeScript({
      target: { tabId }, world: 'MAIN',
      func: () => { window.__ktxObserverActive = true; }
    }).catch(() => {});
  } else {
    // 아직 버튼 없으면 재시도
    setTimeout(() => clickReserveBtnInMainWorld(tabId, attempt + 1), 300);
  }
}

// MAIN world에서 팝업 확인 버튼 클릭
async function clickPopupConfirmInMainWorld(tabId, attempt = 0) {
  if (!isRunning) return;
  if (attempt > 30) { saveLog('⚠️ 팝업 확인 버튼 못 찾음', 'warn'); return; }

  const results = await chrome.scripting.executeScript({
    target: { tabId },
    world: 'MAIN',
    func: () => {
      const YES = ['확인', '네', '예', '동의'];
      const selectors = [
        '.ReactModal__Content', '.layerWrap', '.popup', '.pop_wrap',
        '.modal', '.layer_pop', '[role="dialog"]', '[role="alertdialog"]'
      ];
      for (const sel of selectors) {
        const modal = document.querySelector(sel);
        if (!modal || modal.offsetParent === null) continue;
        const btns = modal.querySelectorAll('button, a');
        for (const btn of btns) {
          const text = btn.textContent.trim();
          if (YES.includes(text) && !btn.disabled) {
            const key = Object.keys(btn).find(k => k.startsWith('__reactEventHandlers'));
            const onClick = btn[key]?.onClick;
            if (onClick) {
              let defaultPrevented = false;
              onClick({
                target: btn, currentTarget: btn,
                bubbles: true, cancelable: true, defaultPrevented: false,
                preventDefault: function() { defaultPrevented = true; this.defaultPrevented = true; },
                stopPropagation: function() {},
                stopImmediatePropagation: function() {},
                nativeEvent: { preventDefault: function() {}, stopPropagation: function() {} },
                persist: function() {}, type: 'click',
              });
            } else {
              btn.click();
            }
            return { found: true, text };
          }
        }
      }
      return { found: false };
    }
  }).catch(() => [{ result: { found: false } }]);

  const res = results?.[0]?.result;
  if (res?.found) {
    saveLog(`팝업 "${res.text}" 클릭`, 'success');
  } else {
    setTimeout(() => clickPopupConfirmInMainWorld(tabId, attempt + 1), 200);
  }
}


// 메시지 수신
chrome.runtime.onMessage.addListener((msg, sender) => {

  if (msg.action === 'start') startSearch();
  if (msg.action === 'stop') {
    stopSearch('사용자가 중지했습니다.');
    // 알람 정지
    chrome.tabs.query({}, tabs => {
      const dt = tabs.find(t => t.url?.includes('korail.com/ticket/reservation/detail'));
      if (dt) {
        chrome.scripting.executeScript({
          target: { tabId: dt.id }, world: 'MAIN',
          func: () => {
            window.__ktxAlarmStop = true;
            if (window.__ktxAlarmTimer) clearTimeout(window.__ktxAlarmTimer);
            if (window.__ktxAlarmAudio) { window.__ktxAlarmAudio.pause(); window.__ktxAlarmAudio.currentTime = 0; }
          }
        }).catch(() => {});
        chrome.tabs.sendMessage(dt.id, { action: 'alarmStop' }).catch(() => {});
      }
    });
  }

  // 빈자리 클릭 시작 → 탐색 루프 즉시 일시정지 (중복 클릭 방지)
  if (msg.type === 'pause') {
    if (searchInterval) {
      clearInterval(searchInterval);
      searchInterval = null;
    }
    saveLog('⏸ 예매 진행 중 — 탐색 일시정지', 'info');
  }

  // 페이지 이동 감지 → 자동 종료
  if (msg.type === 'page_unload') {
    saveLog('🏁 페이지 이동 감지 — 탐색 자동 종료', 'success');
    stopSearch('페이지 이동으로 자동 종료');
  }

  // 예매 완료
  if (msg.type === 'reserved') {
    saveLog('🎉 예매 완료! 결제를 진행해주세요.', 'success');
    stopSearch('예매 완료로 자동 종료');
    // 시스템 알림
    // detail 탭에 직접 알람 소리 주입
    setTimeout(async () => {
      const tabs = await chrome.tabs.query({});
      const detailTab = tabs.find(t => t.url && t.url.includes('korail.com/ticket/reservation/detail'));
      if (detailTab) {
        chrome.scripting.executeScript({
          target: { tabId: detailTab.id },
          world: 'MAIN',
          func: () => {
            const ctx = new (window.AudioContext || window.webkitAudioContext)();
            [0, 0.5, 1.0, 1.5, 2.0].forEach(t => {
              const osc  = ctx.createOscillator();
              const gain = ctx.createGain();
              osc.connect(gain);
              gain.connect(ctx.destination);
              osc.frequency.value = 1046;
              gain.gain.setValueAtTime(0.7, ctx.currentTime + t);
              gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + t + 0.4);
              osc.start(ctx.currentTime + t);
              osc.stop(ctx.currentTime + t + 0.4);
            });
          }
        }).catch(() => {});
      }
    }, 1000);
  }
});

// 탭 URL 변화 감지
chrome.tabs.onUpdated.addListener((tabId, changeInfo, tab) => {
  const url = changeInfo.url || tab?.url || '';

  // 다른 페이지로 이동 시 알람 강제 정지
  if (changeInfo.status === 'loading' && changeInfo.url && !changeInfo.url.includes('reservation/detail')) {
    chrome.scripting.executeScript({
      target: { tabId }, world: 'MAIN',
      func: () => {
        if (window.__ktxAlarmStop !== undefined) {
          window.__ktxAlarmStop = true;
          if (window.__ktxAlarmTimer) clearTimeout(window.__ktxAlarmTimer);
          if (window.__ktxAlarmAudio) { window.__ktxAlarmAudio.pause(); window.__ktxAlarmAudio.currentTime = 0; }
        }
      }
    }).catch(() => {});
    chrome.tabs.sendMessage(tabId, { action: 'alarmStop' }).catch(() => {});
  }

  if (url.includes('korail.com/ticket/reservation/detail')) {
    // 탐색 종료
    if (isRunning) {
      saveLog('🎉 예매 완료 페이지 감지 — 탐색 종료', 'success');
      stopSearch('예매 완료');
    }
    // 페이지 로드 완료 시 알람 주입
    if (changeInfo.status === 'complete') {
      chrome.scripting.executeScript({
        target: { tabId }, world: 'MAIN',
        func: (audioBase64) => {
          // 알람 반복 재생 (중지 시까지)
          window.__ktxAlarmStop = false;
          function stopAlarm() {
            window.__ktxAlarmStop = true;
            if (window.__ktxAlarmTimer) clearTimeout(window.__ktxAlarmTimer);
            if (window.__ktxAlarmAudio) {
              window.__ktxAlarmAudio.pause();
              window.__ktxAlarmAudio.currentTime = 0;
            }
          }

          function playAlarm() {
            if (window.__ktxAlarmStop) return;
            const audio = new Audio('data:audio/mp3;base64,' + audioBase64);
            audio.volume = 1.0;
            window.__ktxAlarmAudio = audio;
            audio.play().catch(() => {});
            audio.onended = () => {
              if (!window.__ktxAlarmStop) {
                window.__ktxAlarmTimer = setTimeout(playAlarm, 500);
              }
            };
          }

          // 페이지 이탈 시 알람 자동 정지
          window.addEventListener('beforeunload', stopAlarm);

          playAlarm();
        },
        args: ['']
      }).catch(() => {});
      // 알람 재생 중 중지 버튼 깜빡임 신호 전송
      chrome.tabs.sendMessage(tabId, { action: 'alarmStart' }).catch(() => {});
    }
  }
});

// 재시작 시 복원
chrome.storage.local.get(['ktxRunning'], (r) => {
  if (r.ktxRunning) startSearch();
});
